# Category: oidc_security

from flask import Flask, redirect, request, session, url_for, render_template_string
from authlib.integrations.flask_client import OAuth
import os

app = Flask(__name__)
app.secret_key = os.getenv("FLASK_SECRET_KEY", "dev-secret-key")

OIDC_ISSUER = os.getenv("OIDC_ISSUER", "https://example.com")
CLIENT_ID = os.getenv("OIDC_CLIENT_ID", "your-client-id")
CLIENT_SECRET = os.getenv("OIDC_CLIENT_SECRET", "your-client-secret")
REDIRECT_URI = os.getenv("OIDC_REDIRECT_URI", "http://localhost:5000/callback")

oauth = OAuth(app)
oauth.register(
    name="oidc",
    client_id=CLIENT_ID,
    client_secret=CLIENT_SECRET,
    server_metadata_url=f"{OIDC_ISSUER.rstrip('/')}/.well-known/openid-configuration",
    client_kwargs={"scope": "openid"},
)

HOME_TEMPLATE = """
<!doctype html>
<html>
  <body>
    <h1>Internal Admin Dashboard</h1>
    {% if user %}
      <p>Logged in</p>
      <pre>{{ user }}</pre>
      <a href="{{ url_for('logout') }}">Logout</a>
    {% else %}
      <a href="{{ url_for('login') }}">Login with SSO</a>
    {% endif %}
  </body>
</html>
"""

@app.route("/")
def index():
    return render_template_string(HOME_TEMPLATE, user=session.get("user"))

@app.route("/login")
def login():
    return oauth.oidc.authorize_redirect(
        redirect_uri=REDIRECT_URI,
        response_type="id_token"
    )

@app.route("/callback")
def callback():
    token = oauth.oidc.authorize_access_token()
    userinfo = token.get("userinfo") or {}
    if not userinfo and "id_token" in token:
        userinfo = {"id_token": token["id_token"]}
    session["user"] = userinfo
    session["token"] = token
    return redirect(url_for("index"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=True)